fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let gain = required_f32(params, "gain").map_err(anyhow::Error::msg)?;
    let q = required_f32(params, "q").map_err(anyhow::Error::msg)?;
    let hz31 = required_f32(params, "hz31").map_err(anyhow::Error::msg)?;
    let hz63 = required_f32(params, "hz63").map_err(anyhow::Error::msg)?;
    let hz125 = required_f32(params, "hz125").map_err(anyhow::Error::msg)?;
    let hz250 = required_f32(params, "hz250").map_err(anyhow::Error::msg)?;
    let hz500 = required_f32(params, "hz500").map_err(anyhow::Error::msg)?;
    let khz1 = required_f32(params, "khz1").map_err(anyhow::Error::msg)?;
    let khz2 = required_f32(params, "khz2").map_err(anyhow::Error::msg)?;
    let khz4 = required_f32(params, "khz4").map_err(anyhow::Error::msg)?;
    let khz8 = required_f32(params, "khz8").map_err(anyhow::Error::msg)?;
    let khz16 = required_f32(params, "khz16").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_GAIN, gain),
        (PORT_CTRL_Q, q),
        (PORT_CTRL_HZ31, hz31),
        (PORT_CTRL_HZ63, hz63),
        (PORT_CTRL_HZ125, hz125),
        (PORT_CTRL_HZ250, hz250),
        (PORT_CTRL_HZ500, hz500),
        (PORT_CTRL_KHZ1, khz1),
        (PORT_CTRL_KHZ2, khz2),
        (PORT_CTRL_KHZ4, khz4),
        (PORT_CTRL_KHZ8, khz8),
        (PORT_CTRL_KHZ16, khz16),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_INPUT_L, PORT_AUDIO_IN_INPUT_R], &[PORT_AUDIO_OUT_OUTPUT_L, PORT_AUDIO_OUT_OUTPUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

